#!/usr/bin/env python3
"""Pytest validations for datasets generated by data_collection_parallel.py."""

import os
import sys
from pathlib import Path

import numpy as np
import pytest
import torch
from torch_geometric.data import InMemoryDataset

sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))
from data_collection_parallel import generate_dataset_parallel, load_object_safetensors  # noqa: E402


def iter_graphs_from_dataset_file(dataset_path: str):
    payload = load_object_safetensors(dataset_path)
    data = payload["data"]
    slices = payload["slices"]

    class _Tmp(InMemoryDataset):
        pass

    ds = _Tmp()
    ds.data = data
    ds.slices = slices
    for idx in range(len(ds)):
        yield ds.get(idx)


def assert_graph_valid(graph, task_type: str):
    assert hasattr(graph, "x") and graph.x is not None, "missing x"

    n = int(graph.x.shape[0])
    assert n > 0, "empty graph"

    if hasattr(graph, "pos") and graph.pos is not None:
        assert graph.pos.shape == (n, 3), f"pos shape mismatch: {tuple(graph.pos.shape)}"

    if hasattr(graph, "edge_index") and graph.edge_index is not None:
        assert graph.edge_index.ndim == 2 and graph.edge_index.shape[0] == 2, (
            f"edge_index shape invalid: {tuple(graph.edge_index.shape)}"
        )

    if hasattr(graph, "edge_attr") and graph.edge_attr is not None:
        assert graph.edge_attr.ndim == 2 and graph.edge_attr.shape[1] == 7, (
            f"edge_attr expected (_,7), got {tuple(graph.edge_attr.shape)}"
        )
        rel = graph.edge_attr[:, :3].cpu().numpy()
        d = graph.edge_attr[:, 3].cpu().numpy()
        d_ref = np.linalg.norm(rel, axis=1)
        assert np.allclose(d, d_ref, atol=1e-5), "edge_attr distance channel mismatch"

    if task_type == "setpoint_prediction":
        assert hasattr(graph, "target") and graph.target is not None, "setpoint graph missing target"
        assert graph.target.shape[0] == n, "target row count mismatch"
        assert graph.target.shape[1] == 4, f"target dim expected 4, got {graph.target.shape[1]}"

        assert hasattr(graph, "y") and graph.y is not None, "setpoint graph missing y"
        assert graph.y.shape[0] == n, "y row count mismatch"
        assert graph.y.shape[1] == 4, f"setpoint y dim expected 4, got {graph.y.shape[1]}"

    elif task_type == "residual_correction":
        assert hasattr(graph, "target") and graph.target is not None, "residual graph missing target"
        assert graph.target.shape[0] == n, "target row count mismatch"
        assert graph.target.shape[1] == 3, f"residual target dim expected 3, got {graph.target.shape[1]}"

        assert hasattr(graph, "y") and graph.y is not None, "residual graph missing y"
        assert graph.y.shape[0] == n, "y row count mismatch"
        assert graph.y.shape[1] == 4, f"residual y dim expected 4, got {graph.y.shape[1]}"


def validate_dataset_file(dataset_path: str, task_type: str):
    assert os.path.exists(dataset_path), f"file does not exist: {dataset_path}"

    graphs = list(iter_graphs_from_dataset_file(dataset_path))
    assert len(graphs) > 0, "no graphs in dataset"

    for graph in graphs:
        assert_graph_valid(graph, task_type)


def run_generation(task_type: str, dataset_name: str):
    cfg = {
        "num_workers": 2,
        "num_episodes": 3,
        "max_steps": 80,
        "dataset_name": dataset_name,
        "dataset_type": "mixed_formations",
        "task_type": task_type,
        "num_obstacles": (0, 3),
        "obstacle_radius_range": (0.5, 1.2),
        "communication_radius": 10.0,
        "include_formation_in_state": True,
        "seed": 123,
        "base_xy_limit": 8.0,
        "altitude_range": (0.5, 4.0),
    }

    if task_type == "residual_correction":
        cfg.update(
            {
                "residual_samples_per_seed": 5,
                "residual_balance_ratio": 0.5,
                "residual_dropout_threshold": 0.1,
            }
        )

    return generate_dataset_parallel(**cfg)


@pytest.mark.parametrize(
    "task_type,dataset_name",
    [
        ("setpoint_prediction", "test_validation"),
        ("residual_correction", "test_residual"),
    ],
)
def test_dataset_generation_and_shapes(task_type: str, dataset_name: str):
    generated_files, _ = run_generation(task_type, dataset_name)
    root = Path(__file__).resolve().parents[1] / "datasets"

    assert generated_files, "no dataset files were generated"
    for _, fname in generated_files.items():
        validate_dataset_file(str(root / fname), task_type)
